// Handle both: Apify returns array as-is OR n8n splits it into individual items
const firstJson = $input.first().json;
const allItems = Array.isArray(firstJson) ? firstJson : $input.all().map(i => i.json);

const ALLOWED_COUNTRIES = new Set([
  'United States','Canada','United Kingdom','Ireland','Germany','France',
  'Netherlands','Belgium','Switzerland','Austria','Luxembourg','Denmark',
  'Sweden','Norway','Finland','Iceland','Spain','Portugal','Italy','Greece',
  'Malta','Cyprus','Poland','Czech Republic','Slovakia','Hungary','Romania',
  'Bulgaria','Croatia','Slovenia','Estonia','Latvia','Lithuania','Serbia',
  'Ukraine','Georgia','Armenia','Moldova'
]);

const jobs = [];
for (const item of allItems) {
  if (item.type !== 'detail') continue;

  const data = item.data || {};
  const opening = data.opening || {};
  const clientData = data.client || {};
  const budgetData = data.budget || {};

  // Geo filter (only when country is known)
  const loc = clientData.location || {};
  const country = typeof loc === 'object' ? (loc.country || '') : '';
  if (country && !ALLOWED_COUNTRIES.has(country)) continue;

  // Budget
  const fixedBudget = budgetData.fixedBudget || 0;
  const hr = budgetData.hourlyRate || {};
  const hourlyMin = hr.min || 0;
  const hourlyMax = hr.max || 0;
  let budget = 'Not specified';
  if (fixedBudget) budget = '$' + fixedBudget.toLocaleString() + ' fixed';
  else if (hourlyMin) budget = '$' + hourlyMin + '\u2013$' + hourlyMax + '/hr';

  // Skills
  const skillsRaw = data.skills || opening.skills || [];
  const skills = skillsRaw.map(s => typeof s === 'object' ? s.name : s).filter(Boolean).slice(0, 8);

  // Client
  const stats = clientData.stats || {};
  const clientRating = (typeof stats === 'object' ? stats.rating : 0) || 0;
  const clientSpent = (typeof stats === 'object' ? stats.totalSpent : 0) || 0;
  const paymentVerified = clientData.paymentMethodVerified || false;
  const applicants = opening.applicants || 0;

  // URL
  let url = item.link || '';
  if (url.includes('?')) url = url.split('?')[0];

  jobs.push({
    title: item.title || 'Untitled',
    description: (opening.description || '').slice(0, 2000),
    url,
    budget,
    fixedBudget,
    hourlyMin,
    skills,
    country: country || 'Unknown',
    clientRating,
    clientSpent,
    paymentVerified,
    applicants
  });
}

if (jobs.length === 0) return [];
return jobs.map(j => ({ json: j }));

const resp = $input.item.json;
const job = $('Parse + Filter Jobs').item.json;

const text = resp.content?.[0]?.text || '{}';
let score = 0, reason = 'Could not score', matched = 0;
try {
  const m = text.match(/\{[\s\S]*?\}/);
  if (m) {
    const p = JSON.parse(m[0]);
    score = parseInt(p.score) || 0;
    reason = p.reason || '';
    matched = parseInt(p.matched) || 0;
  }
} catch(e) {}

return [{ json: { ...job, score, reason, matched } }];
